module tb(); reg clk; reg reset; reg in; wire out; reg out_ref; reg out_dut; reg tb_match; reg [511:0] wavedrom_title; reg wavedrom_enable; initial begin clk = 0; reset = 1; in = 0; end task reset_test(input async=0); bit arfail, srfail, datafail; @(posedge clk); @(posedge clk) reset = 0; repeat(3) @(posedge clk); @(negedge clk) begin datafail = !tb_match; reset = 1; end @(posedge clk) arfail = !tb_match; @(posedge clk) begin srfail = !tb_match; reset = 0; end if (srfail) $display("Hint: Your reset doesn't seem to be working."); else if (arfail && (async || !datafail)) $display("Hint: Your reset should be synchronous, but doesn't appear to be."); endtask task wavedrom_start(input[511:0] title = ""); endtask task wavedrom_stop; #1; endtask stimulus_gen stim1 ( .clk(clk), .in(in), .reset(reset) ); TopModule uut ( .clk(clk), .reset(reset), .in(in), .out(out) ); RefModule ref_mod ( .clk(clk), .reset(reset), .in(in), .out(out_ref) ); always @(posedge clk) begin out_dut = out; end always @(*) tb_match = (out_dut === out_ref); initial begin $dumpfile("wave.vcd"); $dumpvars(1, tb, clk, reset, in, out, out_ref); reset <= 1; @(posedge clk); reset <= 0; // Test sequence // ... end final begin if (stats1.errors_out) $display("Hint: Output 'out' has %0d mismatches. First mismatch occurred at time %0d.", stats1.errors_out, stats1.errortime_out); else $display("SIMULATION PASSED"); end endmodule